CREATE OR REPLACE FUNCTION sync_module_item_data_to_item_data()
RETURNS TRIGGER AS $$
BEGIN
    IF (TG_OP = 'INSERT') THEN
        INSERT INTO item_data (
            item_data_id, item_id, event_crf_id, value,
            ordinal, status_id, deleted, date_created,
            date_updated, owner_id, update_id
        )
        VALUES (
            NEW.item_data_id, NEW.item_id, NEW.event_crf_id, NEW.value,
            NEW.ordinal, NEW.status_id, NEW.deleted, NEW.date_created,
            NEW.date_updated, NEW.owner_id, NEW.update_id
        );
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        UPDATE item_data SET
            item_id = NEW.item_id,
            event_crf_id = NEW.event_crf_id,
            value = NEW.value,
            ordinal = NEW.ordinal,
            status_id = NEW.status_id,
            deleted = NEW.deleted,
            date_created = NEW.date_created,
            date_updated = NEW.date_updated,
            owner_id = NEW.owner_id,
            update_id = NEW.update_id
        WHERE item_data_id = OLD.item_data_id;
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        DELETE FROM item_data WHERE item_data_id = OLD.item_data_id;
        RETURN OLD;
    END IF;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_sync_module_item_data
AFTER INSERT OR UPDATE OR DELETE ON module_item_data
FOR EACH ROW EXECUTE FUNCTION sync_module_item_data_to_item_data();
